INSERT INTO `cadeaux` VALUES (30001,'uploads/week-end-insolite.jpg','Bongo FR Week-end Insolite','Bongo','&lt;p&gt;Quoi de plus efficace pour &amp;eacute;chapper &amp;agrave; la routine qu&amp;rsquo;une &amp;eacute;chapp&amp;eacute;e pleine d&amp;rsquo;originalit&amp;eacute; ? Gr&amp;acirc;ce &amp;agrave; ce coffret cadeau Bongo S&amp;eacute;jour insolite, deux &amp;acirc;mes en qu&amp;ecirc;te d&amp;rsquo;&amp;eacute;vasion pourront profiter d&amp;rsquo;une nuit avec petit-d&amp;eacute;jeuner, &amp;agrave; vivre dans le cadre surprenant d&amp;rsquo;une cabane, d&amp;rsquo;une roulotte, d&amp;rsquo;un bateau ou encore d&amp;rsquo;un h&amp;ocirc;tel &amp;agrave; th&amp;egrave;me. Id&amp;eacute;al pour d&amp;eacute;connecter en duo !&lt;/p&gt;',99.90,0,3),(30002,'uploads/aventure-en-duo.jpg','Bongo FR Aventure en Duo','Bongo','&lt;p&gt;Ce ch&amp;egrave;que-cadeau donne droit &amp;agrave; l&#039;une des activit&amp;eacute;s propos&amp;eacute;es par les organisateurs s&amp;eacute;lectionn&amp;eacute;s.&lt;/p&gt;',39.90,1,3),(30003,'uploads/cinema.jpg','Bongo FR Cinéma & Pop-corn à deux','Bongo','&lt;p&gt;Bongo Giftbox Cin&amp;eacute;ma &amp;amp; Pop-corn &amp;agrave; deux&lt;/p&gt;',34.90,1,3),(30004,'uploads/gastronomie-et-vin.jpg','Bongo FR Gastronomie et Vin','Bongo','&lt;p&gt;Ce Bongo donne droit &amp;agrave; un diner gastronomique pour deux personnes (formule vin compris), &amp;agrave; d&amp;eacute;guster dans l&#039;un des restaurants s&amp;eacute;lectionn&amp;eacute;s.&lt;/p&gt;',119.90,1,3),(30005,'uploads/jours-de-charme.jpg','Bongo FR 2 Jours de Charme','Bongo','&lt;p&gt;Bongo FR 2 Jours de Charme&lt;/p&gt;',74.90,1,3),(30006,'uploads/joyeux-anniversaire.jpg','Bongo FR Joyeux Anniversaire','Bongo','&lt;p&gt;Joyeux Anniversaire&lt;/p&gt;',29.90,1,3),(30007,'uploads/moments-de-bien-etre.jpg','Bongo FR Moments de bien-être','Bongo','&lt;p&gt;Bongo Giftbox Moments de bien-&amp;ecirc;tre&lt;/p&gt;',49.90,1,3),(30008,'uploads/tables-romantiques.jpg','Bongo FR Tables Romantiques','Bongo','&lt;p&gt;Ce Bongo Tables Romantiques est valable pour deux personnes et donne droit &amp;agrave; un diner trois services ou un menu deux services avec vin &amp;agrave; d&amp;eacute;guster dans l&#039;un des restaurants s&amp;eacute;lectionn&amp;eacute;s.&lt;/p&gt;',69.90,1,3),(30009,'uploads/spa-et-massage.jpg','Bongo FR Spa et Massage en Duo','Bongo','&lt;p&gt;Ce ch&amp;egrave;que-cadeau, valable pour deux personnes, donne droit &amp;agrave; l&#039;une des formules propos&amp;eacute;es par les instituts de beaut&amp;eacute; s&amp;eacute;lectionn&amp;eacute;s.&lt;/p&gt;',79.90,1,3),(30010,'uploads/evasion-a-deux.jpg','Bongo FR Evasion a Deux','Bongo','&lt;p&gt;Ce Bongo &amp;Eacute;vasion &amp;agrave; Deux est valable pour deux personnes et donne droit &amp;agrave; l&#039;une des formules vari&amp;eacute;es propos&amp;eacute;es (s&amp;eacute;jours &amp;agrave; l&#039;h&amp;ocirc;tel avec petit d&amp;eacute;jeuner, produits, .) par les &amp;eacute;tablissements s&amp;eacute;lectionn&amp;eacute;s.&lt;/p&gt;',69.90,1,3),(30011,'uploads/merci.jpg','Merci','Wonderbox','&lt;ul class=&quot;description hidden-sm-down&quot;&gt;&lt;br /&gt;\r\n&lt;li&gt;Pour 1 ou 2 personnes&lt;/li&gt;\r\n&lt;li&gt;1 activit&amp;eacute; au choix pour lui dire merci&lt;/li&gt;\r\n&lt;li&gt;990 exp&amp;eacute;riences qui feront plaisir : activit&amp;eacute; amusante, d&amp;eacute;gustation, soin de bien-&amp;ecirc;tre, petit d&amp;eacute;jeuner...&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;Vous voulez dire lui merci d&#039;une mani&amp;egrave;re originale ? Changez du bouquet de fleurs ou de la bo&amp;icirc;te de chocolats et offrez-lui le choix parmi plus de 990 activit&amp;eacute;s relaxantes et amusantes : petit d&amp;eacute;jeuner, d&amp;eacute;gustation de bi&amp;egrave;res, p&amp;eacute;dicure, soin du visage, laser game...&lt;/p&gt;',29.90,1,3),(30012,'uploads/carte-anniversaire.jpg','Carte Joyeux Anniversaire','Wonder e-card','&lt;ul class=&quot;description hidden-sm-down&quot;&gt;&lt;br /&gt;\r\n&lt;li&gt;Cartes cadeaux IKEA, Zalando, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Rituals, Airbnb, Ticketmaster, Foot Locker, Gamma, Deliveroo..&lt;/li&gt;\r\n&lt;li&gt;De 10 &amp;agrave; 150&amp;euro;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;Joyeux anniversaire ! La Wonder-ecard, au solde compris entre 10 et 150&amp;euro;, peut &amp;ecirc;tre &amp;eacute;chang&amp;eacute;e contre des cartes-cadeaux de plus de 70 enseignes dans les domaines de la mode, de la maison et de la d&amp;eacute;coration, du multim&amp;eacute;dia et du lifestyle.&lt;/p&gt;\r\n&lt;p&gt;La Wonder-ecard est &amp;agrave; &amp;eacute;changer contre une ou plusieurs cartes cadeaux de vos enseignes pr&amp;eacute;f&amp;eacute;r&amp;eacute;es : IKEA, Zalando, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Rituals, Airbnb, Ticketmaster, Foot Locker, Gamma, Deliveroo... et bien d&#039;autres, &amp;agrave; retrouver sur le site&amp;nbsp;&lt;a href=&quot;https://www.wonder-ecard.be/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;www.wonder-ecard.be&lt;/a&gt;. Les cartes-cadeaux peuvent ensuite &amp;ecirc;tre utilis&amp;eacute;es pour un achat en magasin et/ou en ligne.&lt;/p&gt;\r\n&lt;p&gt;Valable 1 an.&lt;/p&gt;\r\n&lt;p&gt;Pour profiter de votre Wonder-ecard, rendez-vous sur&amp;nbsp;&lt;a href=&quot;https://www.wonder-ecard.be/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;www.wonder-ecard.be&lt;/a&gt;.&lt;/p&gt;\r\n&lt;p&gt;1. Renseignez le code Wonder-ecard pr&amp;eacute;sent au dos sous la zone &amp;agrave; gratter.&lt;/p&gt;\r\n&lt;p&gt;2. Acc&amp;eacute;dez au montant et &amp;agrave; la date de validit&amp;eacute; de votre Wonder-ecard.&lt;/p&gt;\r\n&lt;p&gt;3. Choisissez une ou plusieurs cartes cadeaux de vos enseignes pr&amp;eacute;f&amp;eacute;r&amp;eacute;es.&lt;/p&gt;\r\n&lt;p&gt;4. Recevez votre carte cadeau enseigne par e-mail et utilisez-la en magasin ou en ligne.&lt;/p&gt;\r\n&lt;p&gt;&lt;em&gt;Ce produit est un produit de la marque Wonder-ecard. Les codes promotionnels, Wonderpass, les cartes cadeaux th&amp;eacute;matiques (consulter les CGV&amp;nbsp;&lt;a href=&quot;https://be.wonderbox.com/fr/cgv.html&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;ici&lt;/a&gt;&amp;nbsp;) et avoirs ne peuvent pas &amp;ecirc;tre utilis&amp;eacute;s pour l&#039;obtention de ce produit sur be.wonderbox.com/fr. Il est non &amp;eacute;changeable et non prolongeable.&lt;/em&gt;&lt;/p&gt;',100.00,1,3),(30013,'uploads/carte-pour-lui.jpg','Carte Pour Lui','Wonder e-card','&lt;ul class=&quot;description hidden-sm-down&quot;&gt;&lt;br /&gt;\r\n&lt;li&gt;Cartes cadeaux Zalando, IKEA, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Element, Airbnb, Ticketmaster, Foot Locker, Gamma, Xbox, Deliveroo...&lt;/li&gt;\r\n&lt;li&gt;De 10 &amp;agrave; 150&amp;euro;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;La Carte Pour lui est faite... pour lui ! La carte r&amp;eacute;unit plus de 70 enseignes s&amp;eacute;lectionn&amp;eacute;es autour de la mode, de la maison et de la d&amp;eacute;coration, du multim&amp;eacute;dia et du lifestyle : Zalando, IKEA, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Element, Airbnb, Ticketmaster, Foot Locker, Gamma, Xbox, Deliveroo...&lt;/p&gt;\r\n&lt;p&gt;La Wonder-ecard permet d&amp;rsquo;obtenir une ou plusieurs cartes cadeaux de vos enseignes pr&amp;eacute;f&amp;eacute;r&amp;eacute;es, &amp;agrave; retrouver sur le site&amp;nbsp;&lt;a href=&quot;https://wonder-ecard.be/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;wonder-ecard.be&lt;/a&gt;&amp;nbsp;et &amp;agrave; utiliser ensuite dans plus de 1 000 points de vente et sites internet.&lt;/p&gt;\r\n&lt;p&gt;Valable 1 an.&lt;/p&gt;\r\n&lt;p&gt;Pour profiter de votre Wonder-ecard, rendez-vous sur&amp;nbsp;&lt;a href=&quot;https://www.wonder-ecard.be/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;www.wonder-ecard.be&lt;/a&gt;.&lt;/p&gt;\r\n&lt;p&gt;1. Renseignez le code Wonder-ecard pr&amp;eacute;sent au dos sous la zone &amp;agrave; gratter.&lt;/p&gt;\r\n&lt;p&gt;2. Acc&amp;eacute;dez au montant et &amp;agrave; la date de validit&amp;eacute; de votre Wonder-ecard.&lt;/p&gt;\r\n&lt;p&gt;3. Choisissez une ou plusieurs cartes cadeaux de vos enseignes pr&amp;eacute;f&amp;eacute;r&amp;eacute;es.&lt;/p&gt;\r\n&lt;p&gt;4. Recevez votre carte cadeau enseigne par e-mail et utilisez-la en magasin ou en ligne.&lt;/p&gt;\r\n&lt;p&gt;&lt;em&gt;Ce produit est un produit de la marque Wonder-ecard. Les codes promotionnels, Wonderpass, les cartes cadeaux th&amp;eacute;matiques (consulter les CGV&amp;nbsp;&lt;a href=&quot;https://be.wonderbox.com/fr/cgv.html&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;ici&lt;/a&gt;&amp;nbsp;) et avoirs ne peuvent pas &amp;ecirc;tre utilis&amp;eacute;s pour l&#039;obtention de ce produit sur be.wonderbox.com/fr. Il est non &amp;eacute;changeable et non prolongeable.&lt;/em&gt;&lt;/p&gt;',100.00,1,3),(30014,'uploads/carte-pour-elle.jpg','Carte Pour Elle','Wonder e-card','&lt;ul class=&quot;description hidden-sm-down&quot;&gt;&lt;br /&gt;\r\n&lt;li&gt;Cartes cadeaux Zalando, IKEA, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Element, Airbnb, Ticketmaster, Foot Locker, Gamma, Xbox, Deliveroo...&lt;/li&gt;\r\n&lt;li&gt;De 10 &amp;agrave; 150&amp;euro;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;La Carte Pour lui est faite... pour lui ! La carte r&amp;eacute;unit plus de 70 enseignes s&amp;eacute;lectionn&amp;eacute;es autour de la mode, de la maison et de la d&amp;eacute;coration, du multim&amp;eacute;dia et du lifestyle : Zalando, IKEA, MediaMarkt, Primark, Coolblue, H&amp;amp;M, INNO, Element, Airbnb, Ticketmaster, Foot Locker, Gamma, Xbox, Deliveroo...&lt;/p&gt;\r\n&lt;p&gt;La Wonder-ecard permet d&amp;rsquo;obtenir une ou plusieurs cartes cadeaux de vos enseignes pr&amp;eacute;f&amp;eacute;r&amp;eacute;es, &amp;agrave; retrouver sur le site&amp;nbsp;&lt;a href=&quot;https://wonder-ecard.be/&quot; target=&quot;_blank&quot; rel=&quo